// Time:  O(n)
// Space: O(n)

// difference array
class Solution {
public:
    int subarraySum(vector<int>& nums) {
        vector<int> diff(size(nums) + 1);
        for (int i = 0; i < size(nums); ++i) {
            ++diff[max(i - nums[i], 0)];
            --diff[i + 1];
        }
        for (int i = 0; i < size(nums); ++i) {
            diff[i + 1] += diff[i];
        }
        int result = 0;
        for (int i = 0; i < size(nums); ++i) {
            result += nums[i] * diff[i];
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(n)

# difference array
class Solution(object):
    def subarraySum(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        diff = [0]*(len(nums)+1)
        for i, x in enumerate(nums):
            diff[max(i-x, 0)] += 1
            diff[i+1] -= 1
        for i in xrange(len(nums)):
            diff[i+1] += diff[i]
        return sum(nums[i]*diff[i] for i in xrange(len(nums)))
